// Deterministic Matching Logic
// Groups records by exact matches on recordId, amount, and date fields
// Calculates match confidence based on number of matching fields

const items = $input.all();
const matchedGroups = {};
const results = [];

// Helper function to normalize values for comparison
function normalizeValue(value) {
  if (value === null || value === undefined) return '';
  return String(value).trim().toLowerCase();
}

// Helper function to normalize date for comparison
function normalizeDate(date) {
  if (!date) return '';
  try {
    const d = new Date(date);
    return d.toISOString().split('T')[0]; // YYYY-MM-DD format
  } catch (e) {
    return String(date).trim();
  }
}

// Helper function to normalize amount for comparison
function normalizeAmount(amount) {
  if (amount === null || amount === undefined) return '';
  const num = parseFloat(String(amount).replace(/[^0-9.-]/g, ''));
  return isNaN(num) ? '' : num.toFixed(2);
}

// Process each item and create matching keys
for (const item of items) {
  const json = item.json;

  const recordId = normalizeValue(json.recordId || json.id || json.transactionId);
  const amount = normalizeAmount(json.amount || json.total || json.value);
  const date = normalizeDate(json.date || json.transactionDate || json.timestamp);

  // Create multiple matching keys with different combinations
  const matchingKeys = [];

  // Exact match on all three fields (highest confidence)
  if (recordId && amount && date) {
    matchingKeys.push({ key: `${recordId}|${amount}|${date}`, matchedFields: ['recordId', 'amount', 'date'], confidence: 1.0 });
  }

  // Match on recordId and amount (high confidence)
  if (recordId && amount) {
    matchingKeys.push({ key: `${recordId}|${amount}`, matchedFields: ['recordId', 'amount'], confidence: 0.85 });
  }

  // Match on recordId and date (high confidence)
  if (recordId && date) {
    matchingKeys.push({ key: `${recordId}|${date}`, matchedFields: ['recordId', 'date'], confidence: 0.85 });
  }

  // Match on amount and date (medium confidence)
  if (amount && date) {
    matchingKeys.push({ key: `${amount}|${date}`, matchedFields: ['amount', 'date'], confidence: 0.7 });
  }

  // Match on recordId only (lower confidence)
  if (recordId) {
    matchingKeys.push({ key: `${recordId}`, matchedFields: ['recordId'], confidence: 0.6 });
  }

  // Store item with its matching keys
  for (const matchKey of matchingKeys) {
    if (!matchedGroups[matchKey.key]) {
      matchedGroups[matchKey.key] = {
        items: [],
        matchedFields: matchKey.matchedFields,
        baseConfidence: matchKey.confidence
      };
    }
    matchedGroups[matchKey.key].items.push(json);
  }
}

// Process matched groups and create output
for (const [key, group] of Object.entries(matchedGroups)) {
  if (group.items.length > 1) {
    // Multiple items matched - potential reconciliation
    const matchCount = group.items.length;
    const confidence = group.baseConfidence * Math.min(1.0, matchCount / 2); // Adjust confidence based on match count

    results.push({
      matchKey: key,
      matchedFields: group.matchedFields,
      matchCount: matchCount,
      confidence: parseFloat(confidence.toFixed(2)),
      matchType: 'deterministic',
      records: group.items,
      status: confidence >= 0.8 ? 'high_confidence' : 'medium_confidence'
    });
  } else if (group.items.length === 1) {
    // Single item - no match found
    results.push({
      matchKey: key,
      matchedFields: group.matchedFields,
      matchCount: 1,
      confidence: 0,
      matchType: 'no_match',
      records: group.items,
      status: 'unmatched'
    });
  }
}

// Return results
return results.map(result => ({ json: result }));

