// Calculate final confidence scores by combining deterministic and AI fuzzy match scores
// Normalize to 0-1 range and add audit trail metadata

const item = $input.item.json;

// Extract scores from different matching stages
const deterministicScore = item.deterministicMatchScore || 0;
const aiScore = item.aiMatchScore || 0;
const hasAiMatch = item.aiMatchScore !== undefined;

// Weight configuration
const DETERMINISTIC_WEIGHT = 0.6;
const AI_WEIGHT = 0.4;

// Calculate combined confidence score
let finalConfidence;
if (hasAiMatch) {
  // Combine both scores with weights
  finalConfidence = (deterministicScore * DETERMINISTIC_WEIGHT) + (aiScore * AI_WEIGHT);
} else {
  // Only deterministic match available
  finalConfidence = deterministicScore;
}

// Normalize to 0-1 range
finalConfidence = Math.max(0, Math.min(1, finalConfidence));

// Determine confidence level
let confidenceLevel;
if (finalConfidence >= 0.9) {
  confidenceLevel = 'HIGH';
} else if (finalConfidence >= 0.7) {
  confidenceLevel = 'MEDIUM';
} else if (finalConfidence >= 0.5) {
  confidenceLevel = 'LOW';
} else {
  confidenceLevel = 'VERY_LOW';
}

// Build audit trail
const auditTrail = {
  timestamp: new Date().toISOString(),
  deterministicScore: deterministicScore,
  aiScore: hasAiMatch ? aiScore : null,
  finalConfidence: finalConfidence,
  confidenceLevel: confidenceLevel,
  matchingMethod: hasAiMatch ? 'HYBRID' : 'DETERMINISTIC',
  weights: {
    deterministic: DETERMINISTIC_WEIGHT,
    ai: AI_WEIGHT
  }
};

// Return enriched item with confidence scores and audit trail
return {
  json: {
    ...item,
    finalConfidence: finalConfidence,
    confidenceLevel: confidenceLevel,
    confidencePercentage: Math.round(finalConfidence * 100),
    auditTrail: auditTrail
  }
};

